class VisionEngine(QThread):
    # Signals emitted every frame
    frame_ready     = pyqtSignal(np.ndarray)  # Combined stereo frame (H, W*2, 3)
    telemetry_ready = pyqtSignal(dict)        # FPS, latency, pan, tilt, conf, depth, status

    # Key methods
    def setup_model(self)         # Load/reload YOLO model from CONFIG['MODEL_PATH']
    def setup_matrices(self)      # Load stereo maps + laser homography from .npz files
    def setup(self)               # Open cameras at CAM_L_IDX / CAM_R_IDX
    def run(self)                 # Main inference loop — called by .start()
    def stop(self)                # Graceful shutdown: stops loop, closes cameras, disconnects HW
    def toggle_laser(self)        # Toggle laser intent (preserved across reconnects)
    def reconnect_hardware(self)  # Force immediate hardware reconnect (bypass cooldown)

# In vision_engine.py — setup_model()
model_path = CONFIG['MODEL_PATH'].lower()

if 'pose' in model_path:
    self.task = 'pose'       # Use shoulder keypoints [5],[6]
elif 'seg' in model_path:
    self.task = 'seg'        # Use segmentation mask centroid
else:
    self.task = 'detect'     # Use bounding box center

self.model = YOLO(CONFIG['MODEL_PATH'])
